(function() {
  'use strict';
  var btn = document.getElementById('calcBtn');
  var result = document.getElementById('result');
  function calc() {
    var price = parseFloat(document.getElementById('rvPrice').value) || 0;
    var down = parseFloat(document.getElementById('rvDown').value) || 0;
    var rate = parseFloat(document.getElementById('rvRate').value) || 0;
    var years = parseFloat(document.getElementById('rvTerm').value) || 0;
    var P = price - down;
    var r = rate / 100 / 12;
    var n = years * 12;
    var monthly = 0;
    if (r > 0 && n > 0) {
      monthly = P * (r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1);
    } else if (n > 0) {
      monthly = P / n;
    }
    var totalCost = monthly * n;
    var totalInt = totalCost - P;
    function $(v) { return '$' + v.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ','); }
    document.getElementById('rvMonthly').textContent = $(monthly);
    document.getElementById('rvTotalInt').textContent = $(totalInt);
    document.getElementById('rvTotalCost').textContent = $(totalCost + down);
    document.getElementById('rvLoanAmt').textContent = $(P);
    result.classList.add('visible');
  }
  btn.addEventListener('click', calc);
  document.querySelectorAll('#rvPrice,#rvDown,#rvRate,#rvTerm').forEach(function(el) {
    el.addEventListener('keydown', function(e) { if (e.key === 'Enter') calc(); });
  });
})();

