(function() {
  'use strict';
  var btn = document.getElementById('calcBtn');
  var result = document.getElementById('result');
  function calc() {
    var price = parseFloat(document.getElementById('depPrice').value) || 0;
    var years = parseInt(document.getElementById('depYears').value) || 0;
    var firstPct = parseFloat(document.getElementById('depFirst').value) / 100 || 0;
    var annualPct = parseFloat(document.getElementById('depAnnual').value) / 100 || 0;
    var value = price * (1 - firstPct);
    var y1 = value;
    for (var i = 1; i < years; i++) {
      value = value * (1 - annualPct);
    }
    if (years === 0) value = price;
    function $(v) { return '$' + v.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ','); }
    document.getElementById('depFinal').textContent = $(value);
    document.getElementById('depLost').textContent = $(price - value);
    document.getElementById('depPct').textContent = (value / price * 100).toFixed(1) + '%';
    document.getElementById('depY1').textContent = $(y1);
    result.classList.add('visible');
  }
  btn.addEventListener('click', calc);
  document.querySelectorAll('#depPrice,#depYears,#depFirst,#depAnnual').forEach(function(el) {
    el.addEventListener('keydown', function(e) { if (e.key === 'Enter') calc(); });
  });
})();

