    document.getElementById('wtAvail').textContent = fmt(avail);
    document.getElementById('wtPax').textContent = fmt(paxWt);
    document.getElementById('wtFluids').textContent = fmt(fluidWt);
    if (avail < 0) document.getElementById('wtAvail').style.color = '#ef4444';
    else document.getElementById('wtAvail').style.color = '';
    result.classList.add('visible');
  }
  btn.addEventListener('click', calc);
  document.querySelectorAll('#wtGvwr,#wtUvw,#wtPassengers,#wtAvgWeight,#wtWater,#wtPropane').forEach(function(el) {
    el.addEventListener('keydown', function(e) { if (e.key === 'Enter') calc(); });
