(function() {
  'use strict';
  var btn = document.getElementById('calcBtn');
  var result = document.getElementById('result');
  var appliances = {
    genAC: { running: 1800, starting: 2800 },
    genFridge: { running: 150, starting: 600 },
    genMicro: { running: 1000, starting: 1500 },
    genTV: { running: 200, starting: 200 },
    genHeat: { running: 1500, starting: 1500 }
  };
  function calc() {
    var totalRunning = 0;
    var maxSurge = 0;
    var ids = ['genAC', 'genFridge', 'genMicro', 'genTV', 'genHeat'];
    ids.forEach(function(id) {
      var qty = parseInt(document.getElementById(id).value) || 0;
      var a = appliances[id];
      totalRunning += a.running * qty;
      var surge = (a.starting - a.running) * qty;
      if (surge > maxSurge) maxSurge = surge;
    });
    var extra = parseFloat(document.getElementById('genExtra').value) || 0;
    totalRunning += extra;
    var peakStarting = totalRunning + maxSurge;
    var recommended = Math.ceil((peakStarting * 1.2) / 500) * 500;
    function fmt(v) { return v.toLocaleString() + 'W'; }
    document.getElementById('genRec').textContent = fmt(recommended) + '+';
    document.getElementById('genPeak').textContent = fmt(peakStarting);
    document.getElementById('genRunning').textContent = fmt(totalRunning);
    document.getElementById('genSurge').textContent = fmt(maxSurge);
    result.classList.add('visible');
  }
  btn.addEventListener('click', calc);
  document.querySelectorAll('#genAC,#genFridge,#genMicro,#genTV,#genHeat,#genExtra').forEach(function(el) {
    el.addEventListener('keydown', function(e) { if (e.key === 'Enter') calc(); });
  });
})();

