  function calc() {
    var val = parseFloat(document.getElementById('nmValue').value) || 0;
    var from = document.getElementById('nmFrom').value;
    var nm, mi, km;
    if (from === 'nm') {
      nm = val; mi = val * 1.15078; km = val * 1.852;
    } else if (from === 'mi') {
      mi = val; nm = val * 0.86898; km = val * 1.60934;
    } else {
      km = val; nm = val / 1.852; mi = val / 1.60934;
    }
    var m = km * 1000;
    document.getElementById('nmNm').textContent = nm.toFixed(4);
    document.getElementById('nmMi').textContent = mi.toFixed(4);
    document.getElementById('nmKm').textContent = km.toFixed(4);
