    var upsFuel = upsRate * 0.125;
    var ups = upsRate + upsFuel;
    var fedexRate = (fedexBase + weight * 0.93) * zone * service + resi;
    var fedexFuel = fedexRate * 0.12;
    var fedex = fedexRate + fedexFuel;
