(function() {
  'use strict';
  var btn = document.getElementById('calcBtn');
  var result = document.getElementById('result');
  function calc() {
    var bL = parseFloat(document.getElementById('palBoxL').value) || 0;
    var bW = parseFloat(document.getElementById('palBoxW').value) || 0;
    var bH = parseFloat(document.getElementById('palBoxH').value) || 0;
    var bWt = parseFloat(document.getElementById('palBoxWt').value) || 0;
    var pL = parseFloat(document.getElementById('palL').value) || 48;
    var pW = parseFloat(document.getElementById('palW').value) || 40;
    var maxH = parseFloat(document.getElementById('palMaxH').value) || 48;
    var maxWt = parseFloat(document.getElementById('palMaxWt').value) || 2500;
    var orient1 = Math.floor(pL / bL) * Math.floor(pW / bW);
    var orient2 = Math.floor(pL / bW) * Math.floor(pW / bL);
    var perLayer = Math.max(orient1, orient2);
    var bestL = orient1 >= orient2 ? bL : bW;
    var bestW = orient1 >= orient2 ? bW : bL;
    var layers = bH > 0 ? Math.floor(maxH / bH) : 0;
    var totalBySpace = perLayer * layers;
    var totalByWeight = bWt > 0 ? Math.floor(maxWt / bWt) : totalBySpace;
    var total = Math.min(totalBySpace, totalByWeight);
    var limiting = totalByWeight < totalBySpace ? 'Weight' : 'Height/Space';
    var usedArea = perLayer * bestL * bestW;
    var palletArea = pL * pW;
    var util = palletArea > 0 ? (usedArea / palletArea * 100) : 0;
    var totalWt = total * bWt;
    document.getElementById('palTotal').textContent = total + ' boxes';
    document.getElementById('palPerLayer').textContent = perLayer + ' boxes';
    document.getElementById('palLayers').textContent = Math.min(layers, Math.ceil(total / perLayer));
    document.getElementById('palWeight').textContent = totalWt.toLocaleString() + ' lbs';
    document.getElementById('palUtil').textContent = util.toFixed(1) + '%';
    document.getElementById('palLimit').textContent = limiting;
    result.classList.add('visible');
  }
  btn.addEventListener('click', calc);
  document.querySelectorAll('#palBoxL,#palBoxW,#palBoxH,#palBoxWt,#palL,#palW,#palMaxH,#palMaxWt').forEach(function(el) {
    el.addEventListener('keydown', function(e) { if (e.key === 'Enter') calc(); });
  });
})();

(function() {
  'use strict';
  var btn = document.getElementById('calcBtn');
  var result = document.getElementById('result');
  function calc() {
    var dims = document.getElementById('clContainer').value.split(',');
    var cL = parseFloat(dims[0]); var cW = parseFloat(dims[1]);
    var cH = parseFloat(dims[2]); var maxWt = parseFloat(dims[3]);
    var uL = parseFloat(document.getElementById('clUnitL').value) || 0;
    var uW = parseFloat(document.getElementById('clUnitW').value) || 0;
    var uH = parseFloat(document.getElementById('clUnitH').value) || 0;
    var uWt = parseFloat(document.getElementById('clUnitWt').value) || 0;
    var o1 = Math.floor(cL / uL) * Math.floor(cW / uW) * Math.floor(cH / uH);
    var o2 = Math.floor(cL / uW) * Math.floor(cW / uL) * Math.floor(cH / uH);
    var volUnits = Math.max(o1, o2);
    var wtUnits = uWt > 0 ? Math.floor(maxWt / uWt) : volUnits;
    var maxLoad = Math.min(volUnits, wtUnits);
    var unitVol = uL * uW * uH;
    var containerVol = cL * cW * cH;
    var util = containerVol > 0 ? ((maxLoad * unitVol) / containerVol * 100) : 0;
    var totalWt = maxLoad * uWt;
    var limiting = wtUnits < volUnits ? 'Weight' : 'Volume';
    document.getElementById('clUnitsVol').textContent = volUnits.toLocaleString() + ' units';
    document.getElementById('clUnitsWt').textContent = wtUnits.toLocaleString() + ' units';
    document.getElementById('clMax').textContent = maxLoad.toLocaleString() + ' units';
    document.getElementById('clUtil').textContent = util.toFixed(1) + '%';
    document.getElementById('clTotalWt').textContent = totalWt.toLocaleString() + ' lbs';
    document.getElementById('clLimit').textContent = limiting;
    result.classList.add('visible');
  }
