      mpf = Math.max(mpf, 31.67);
      mpf = Math.min(mpf, 614.35);
    }
    var totalFees = duty + mpf + broker;
    var totalLanded = custVal + totalFees;
    var effRate = value > 0 ? (totalFees / value * 100) : 0;
    function $(v) { return '$' + v.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ','); }
