    document.getElementById('cdDuty').textContent = $(duty);
    document.getElementById('cdMpfAmt').textContent = $(mpf);
    document.getElementById('cdTotal').textContent = $(totalLanded);
    document.getElementById('cdEffRate').textContent = effRate.toFixed(2) + '%';
    document.getElementById('cdFees').textContent = $(totalFees);
    result.classList.add('visible');
  }
