  });
})();

(function() {
  'use strict';
  var btn = document.getElementById('calcBtn');
  var result = document.getElementById('result');
  var shipDateInput = document.getElementById('ttShipDate');
  var today = new Date();
  shipDateInput.value = today.toISOString().split('T')[0];
  function addBusinessDays(date, days) {
    var d = new Date(date);
    var added = 0;
    while (added < days) {
      d.setDate(d.getDate() + 1);
      var dow = d.getDay();
      if (dow !== 0 && dow !== 6) added++;
    }
    return d;
  }
  function formatDate(d) {
    var days = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
    var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    return days[d.getDay()] + ', ' + months[d.getMonth()] + ' ' + d.getDate() + ', ' + d.getFullYear();
  }
  function calc() {
    var shipDate = new Date(document.getElementById('ttShipDate').value + 'T12:00:00');
    if (isNaN(shipDate.getTime())) return;
    var maxTransit = parseInt(document.getElementById('ttService').value) || 5;
    var zoneFactor = parseFloat(document.getElementById('ttZone').value) || 0.8;
    var buffer = parseInt(document.getElementById('ttBuffer').value) || 0;
    var transitDays = Math.max(1, Math.ceil(maxTransit * zoneFactor));
    var estDelivery = addBusinessDays(shipDate, transitDays + buffer);
    var latestDelivery = addBusinessDays(shipDate, maxTransit + buffer + 1);
    var calDays = Math.round((estDelivery - shipDate) / (1000 * 60 * 60 * 24));
    document.getElementById('ttDelivery').textContent = formatDate(estDelivery);
    document.getElementById('ttDays').textContent = transitDays + ' days';
    document.getElementById('ttCalDays').textContent = calDays + ' days';
    document.getElementById('ttLatest').textContent = formatDate(latestDelivery);
    result.classList.add('visible');
  }
  btn.addEventListener('click', calc);
  document.querySelectorAll('#ttShipDate,#ttService,#ttZone,#ttBuffer').forEach(function(el) {
    el.addEventListener('keydown', function(e) { if (e.key === 'Enter') calc(); });
  });
})();

(function() {
  'use strict';
  var btn = document.getElementById('calcBtn');
  var result = document.getElementById('result');
  var rates = { ups: 1.05, fedex: 1.00, usps: 2.70 };
  function calc() {
    var value = parseFloat(document.getElementById('piValue').value) || 0;
    var carrier = document.getElementById('piCarrier').value;
    var included = parseFloat(document.getElementById('piIncluded').value) || 0;
    var pkgs = parseFloat(document.getElementById('piPackages').value) || 1;
    var rate = rates[carrier] || 1.05;
    var insurable = Math.max(0, value - included);
    var carrierCost = Math.ceil(insurable / 100) * rate * pkgs;
    var thirdParty = (value * 0.008) * pkgs;
    thirdParty = Math.max(thirdParty, 1.50 * pkgs);
    var savings = carrierCost - thirdParty;
    var pct = value > 0 ? (carrierCost / (value * pkgs) * 100) : 0;
    function $(v) { return '$' + v.toFixed(2); }
    document.getElementById('piCarrierCost').textContent = $(carrierCost);
    document.getElementById('piThirdParty').textContent = '~' + $(thirdParty);
    document.getElementById('piSavings').textContent = savings > 0 ? $(savings) + ' with 3rd party' : 'Carrier is cheaper';
    document.getElementById('piPct').textContent = pct.toFixed(2) + '%';
    result.classList.add('visible');
  }
  btn.addEventListener('click', calc);
  document.querySelectorAll('#piValue,#piCarrier,#piIncluded,#piPackages').forEach(function(el) {
    el.addEventListener('keydown', function(e) { if (e.key === 'Enter') calc(); });
  });
})();
